  `request_source` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '请求来源（如：iPhone微信、Chrome浏览器等）',
  `is_error` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否错误',
